// src/schemas/recurringTemplate.ts
import { z } from 'zod';

export const RecurringTemplateSchema = z.object({
  id: z.string().uuid(),
  amount: z.number().positive().max(99999.99),
  categoryId: z.string(),
  merchantName: z.string().min(1).max(100),
  frequency: z.enum(['weekly', 'monthly', 'yearly']),
  startDate: z.string().date(),
  endDate: z.string().date().nullable(),
  nextOccurrence: z.string().date(),
  paymentMethod: z.enum(['cash', 'debit_card', 'credit_card', 'upi_other']),
  note: z.string().max(100).optional(),
  status: z.enum(['active', 'paused']),
  createdAt: z.string().datetime(),
});

// src/repositories/RecurringTemplateRepository.ts
import { db } from '../db';
import type { RecurringTemplate } from '../types';

export class RecurringTemplateRepository {
  async findActiveTemplates(): Promise<RecurringTemplate[]> {
    return db.recurringTemplates.where('status').equals('active').toArray();
  }

  async deleteTemplatePreservingHistory(templateId: string): Promise<void> {
    await db.transaction('rw', [db.recurringTemplates, db.expenses], async () => {
      await db.expenses.where('recurringTemplateId').equals(templateId).modify({ recurringTemplateId: null });
      await db.recurringTemplates.delete(templateId);
    });
  }
}

// src/hooks/useUpcomingRecurring.ts
import { useQuery } from '@tanstack/react-query';
import { recurringTemplateRepo } from '../repositories';

export function useUpcomingRecurring(month: string) {
  return useQuery({
    queryKey: ['recurring-templates', 'upcoming', month],
    queryFn: () => recurringTemplateRepo.findUpcomingOccurrences(month),
    staleTime: 60_000,
  });
}

