// src/db.ts — Schema version 2: adds RecurringTemplate
import Dexie, { type Table } from 'dexie';

export class CashPulseDB extends Dexie {
  expenses!: Table<Expense>;
  categories!: Table<Category>;
  recurringTemplates!: Table<RecurringTemplate>;

  constructor() {
    super('cashpulse');
    this.version(1).stores({
      expenses: '++id, categoryId, date',
      categories: '++id',
    });
    this.version(2).stores({
      expenses: '++id, categoryId, date, recurringTemplateId',
      categories: '++id',
      recurringTemplates: '++id, categoryId, status, nextOccurrence',
    });
  }
}
export const db = new CashPulseDB();

// src/utils/computeOccurrences.ts
export function computeUpcomingOccurrences(
  template: RecurringTemplate,
  rangeStart: Date,
  rangeEnd: Date,
): Date[] {
  const occurrences: Date[] = [];
  let current = new Date(template.startDate);
  while (current <= rangeEnd) {
    if (current >= rangeStart && (!template.endDate || current <= new Date(template.endDate))) {
      occurrences.push(new Date(current));
    }
    switch (template.frequency) {
      case 'weekly': current.setDate(current.getDate() + 7); break;
      case 'monthly': current.setMonth(current.getMonth() + 1); break;
      case 'yearly': current.setFullYear(current.getFullYear() + 1); break;
    }
  }
  return occurrences;
}
